func TestMergeMinimalExisting(t *testing.T) {
	existing := []byte(`{}`)
	generated := []byte(`{
		"$schema": "https://json.schemastore.org/claude-code-settings.json",
		"_comment": "Generated by chunk init.",
		"permissions": {"allow": ["Bash(chunk:*)"]},
		"hooks": {
			"PreToolUse": [{"matcher": "Bash(git commit*)", "hooks": [{"type": "command", "command": "test", "timeout": 60}]}]
		}
	}`)

	result, err := Merge(existing, generated)
	assert.NilError(t, err)
	assert.Assert(t, result.Changed)

	var merged map[string]interface{}
	assert.NilError(t, json.Unmarshal(result.Merged, &merged))
	assert.Equal(t, merged["$schema"], "https://json.schemastore.org/claude-code-settings.json")
	assert.Equal(t, merged["_comment"], "Generated by chunk init.")
}

func TestMergePreservesUnknownKeys(t *testing.T) {
	existing := []byte(`{
		"env": {"FOO": "bar"},
		"model": "claude-sonnet",
		"permissions": {"allow": ["Read"]}
	}`)
	generated := []byte(`{
		"$schema": "https://json.schemastore.org/claude-code-settings.json",
		"_comment": "Generated by chunk init.",
		"permissions": {"allow": ["Bash(chunk:*)"]}
	}`)

	result, err := Merge(existing, generated)
	assert.NilError(t, err)
	assert.Assert(t, result.Changed)

	var merged map[string]interface{}
	assert.NilError(t, json.Unmarshal(result.Merged, &merged))

	// Unknown keys preserved.
	env := merged["env"].(map[string]interface{})
	assert.Equal(t, env["FOO"], "bar")
	assert.Equal(t, merged["model"], "claude-sonnet")
}

func TestMergePermissionsAllowUnion(t *testing.T) {
	existing := []byte(`{"permissions": {"allow": ["Read", "Write"]}}`)
	generated := []byte(`{"permissions": {"allow": ["Bash(chunk:*)", "Read"]}}`)

	result, err := Merge(existing, generated)
	assert.NilError(t, err)

	var merged map[string]interface{}
	assert.NilError(t, json.Unmarshal(result.Merged, &merged))

	perms := merged["permissions"].(map[string]interface{})
	allow := toStringSlice(perms["allow"])

	// All three values present, sorted, no duplicates.
	assert.DeepEqual(t, allow, []string{"Bash(chunk:*)", "Read", "Write"})
}

